const menuBtn=document.querySelector(".fa-bars"),navMenu=document.querySelector(".nav-links"),navLinks=document.querySelectorAll(".nav-links a"),nav=document.querySelector("nav");function closeMenu(){navMenu.classList.remove("active"),menuBtn.classList.remove("active"),overlay.classList.remove("active")}navLinks.forEach(e=>{e.addEventListener("click",function(){navLinks.forEach(e=>e.classList.remove("nav-active")),this.classList.add("nav-active"),closeMenu()})}),document.addEventListener("click",e=>{navMenu.contains(e.target)||menuBtn.contains(e.target)||closeMenu()}),window.addEventListener("scroll",function(){window.scrollY>50?nav.classList.add("scrolled"):nav.classList.remove("scrolled")});const overlay=document.querySelector(".nav-overlay");menuBtn.addEventListener("click",()=>{navMenu.classList.toggle("active"),menuBtn.classList.toggle("active"),overlay.classList.toggle("active")}),overlay.addEventListener("click",closeMenu);